    private static final Injector injector = new ApplicationInjectorFactory()
        .add(new EntityModuleWithPropertyFactoryForBenchmarking())
        .getInjector();
    private static final ISerialiser jacksonDeserialiser = createSerialiserWithJackson(
        new FactoryForTestingEntities(injector.getInstance(EntityFactory.class), new Date()).getFactory(),
        new ProvidedSerialisationClassProvider(entityTypesSet().toArray(new Class<?>[0])),
        new SerialisationTypeEncoder(),
        new IdOnlyProxiedEntityTypeCacheForTests()
    );

    @State(Scope.Thread)
    public static class BenchmarkState {
        public ByteArrayInputStream centreDiscardingObjectStream;
        public ByteArrayInputStream graphiQLQueryObjectStream;
        public ByteArrayInputStream centreValidationModifiedPropertiesHolderStream;
        public ByteArrayInputStream savingInfoHolderStream;
        public ByteArrayInputStream centreContextHolderStream;

        @Setup(Level.Invocation)
        public void setUp() {
            centreDiscardingObjectStream = new ByteArrayInputStream(centreDiscardingObjectJson.getBytes(UTF_8));
            graphiQLQueryObjectStream = new ByteArrayInputStream(graphiQLQueryObjectJson.getBytes(UTF_8));
            centreValidationModifiedPropertiesHolderStream = new ByteArrayInputStream(centreValidationModifiedPropertiesHolderJson.getBytes(UTF_8));
            savingInfoHolderStream = new ByteArrayInputStream(savingInfoHolderJson.getBytes(UTF_8));
            centreContextHolderStream = new ByteArrayInputStream(centreContextHolderJson.getBytes(UTF_8));
        }
    }

    @Benchmark
    public void deserialisingCentreDiscardingObject(final Blackhole blackhole, final BenchmarkState state) {
        blackhole.consume(jacksonDeserialiser.deserialise(state.centreDiscardingObjectStream, Map.class));
    }

    @Benchmark
    public void deserialisingGraphiQLQueryObject(final Blackhole blackhole, final BenchmarkState state) {
        blackhole.consume(jacksonDeserialiser.deserialise(state.graphiQLQueryObjectStream, Map.class));
    }

    @Benchmark
    public void deserialisingCentreValidationModifiedPropertiesHolder(final Blackhole blackhole, final BenchmarkState state) {
        blackhole.consume(jacksonDeserialiser.deserialise(state.centreValidationModifiedPropertiesHolderStream, Map.class));
    }

    @Benchmark
    public void deserialisingSavingInfoHolder(final Blackhole blackhole, final BenchmarkState state) {
        blackhole.consume(jacksonDeserialiser.deserialise(state.savingInfoHolderStream, SavingInfoHolder.class));
    }

    @Benchmark
    public void deserialisingCentreContextHolder(final Blackhole blackhole, final BenchmarkState state) {
        blackhole.consume(jacksonDeserialiser.deserialise(state.centreContextHolderStream, CentreContextHolder.class));
    }

